//import './/App.css'
import React from 'react';

const tasksDe=[
  {text: 'Revisar Examenes', completed: true},
  {text: 'Escribir', completed: true},
  {text: 'Correr', completed: true},
  {text: 'Caminar', completed: false},
]

function App() {
  const [tasksDe, setTasks]= React.useState(tasksDe);
  const numberTaskCompleted=
  tasks.filter((task)=> task.completed).length;


  return (

    <React.Fragment>
      <Header completados={10} total= {15} />

      <Search/>
